import { appRef, Routes, Route } from "mybricks";
import ScoreQueryPage from "./pages/ScoreQueryPage";

/**
 * @title 学生成绩查询系统
 */
export default appRef(() => {
  return (
    <Routes>
      <Route index element={<ScoreQueryPage />} />
    </Routes>
  );
});

import { pageRef } from "mybricks";
import Header from "./Header";
import SearchBar from "./SearchBar";
import ScoreList from "./ScoreList";
import PaginationArea from "./PaginationArea";
import css from "./index.less";

/**
 * @title 成绩查询页面
 */
export default pageRef(() => {
  return (
    <div className={css.pageContainer}>
      <Header />
      <div className={css.contentWrapper}>
        <SearchBar />
        <ScoreList />
        <PaginationArea />
      </div>
    </div>
  );
});

.pageContainer {
  position: relative;
  width: 100%;
  height: 100%;
  background-color: #f5f5f5;
  display: flex;
  flex-direction: column;
}

.contentWrapper {
  position: relative;
  flex: 1;
  padding: 16px;
  overflow: auto;
}

import { comRef } from "mybricks";
import TitleArea from "./TitleArea";
import css from "./index.less";

/**
 * @summary 页面头部
 */
export default comRef(() => {
  return (
    <div className={css.headerContainer}>
      <TitleArea />
    </div>
  );
});

.headerContainer {
  position: relative;
  width: 100%;
  height: 60px;
  background-color: #fff;
  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.08);
  display: flex;
  align-items: center;
  padding: 0 24px;
  flex-shrink: 0;
}

import { comRef } from "mybricks";
import { Typography } from "antd";
import css from "./index.less";

const { Title } = Typography;

/**
 * @summary 标题区域
 */
export default comRef(() => {
  return (
    <Title level={4} className={css.pageTitle}>
      学生成绩查询
    </Title>
  );
});

.pageTitle {
  margin: 0 !important;
  font-size: 18px;
  font-weight: 500;
  color: #262626;
}

import { comRef } from "mybricks";
import NameInput from "./NameInput";
import StudentIdInput from "./StudentIdInput";
import ClassSelect from "./ClassSelect";
import QueryButton from "./QueryButton";
import css from "./index.less";

/**
 * @summary 搜索筛选区
 */
export default comRef(() => {
  return (
    <div className={css.searchBarContainer}>
      <NameInput />
      <StudentIdInput />
      <ClassSelect />
      <QueryButton />
    </div>
  );
});

.searchBarContainer {
  position: relative;
  width: 100%;
  background-color: #fff;
  border-radius: 8px;
  padding: 20px 24px;
  display: flex;
  align-items: center;
  gap: 16px;
  flex-wrap: wrap;
}

import { comRef } from "mybricks";
import { Input } from "antd";
import css from "./index.less";

/**
 * @summary 学生姓名输入框
 * @prop {string} value - 输入值
 * @event {updateName} 更新姓名 - flowchart LR; A[调用 store.setSearchName]
 */
export default comRef(({ store }) => {
  return (
    <Input
      className={css.nameInput}
      placeholder="请输入学生姓名"
      value={store.searchName}
      allowClear
      /** onChange:updateName */
      onChange={(e) => store.setSearchName(e.target.value)}
    />
  );
});

.nameInput {
  width: 180px;
}

import { comRef } from "mybricks";
import { Input } from "antd";
import css from "./index.less";

/**
 * @summary 学号输入框
 * @prop {string} value - 输入值
 * @event {updateStudentId} 更新学号 - flowchart LR; A[调用 store.setSearchStudentId]
 */
export default comRef(({ store }) => {
  return (
    <Input
      className={css.studentIdInput}
      placeholder="请输入学号"
      value={store.searchStudentId}
      allowClear
      /** onChange:updateStudentId */
      onChange={(e) => store.setSearchStudentId(e.target.value)}
    />
  );
});

.studentIdInput {
  width: 180px;
}

import { comRef } from "mybricks";
import { Select } from "antd";
import css from "./index.less";

/**
 * @summary 班级选择器
 * @prop {string} value - 选中值
 * @event {updateClass} 更新班级 - flowchart LR; A[调用 store.setSearchClass]
 */
export default comRef(({ store }) => {
  return (
    <Select
      className={css.classSelect}
      placeholder="请选择班级"
      value={store.searchClass}
      allowClear
      /** onChange:updateClass */
      onChange={(value) => store.setSearchClass(value)}
    >
      {store.classOptions.map((item) => (
        <Select.Option key={item.value} value={item.value}>
          {item.label}
        </Select.Option>
      ))}
    </Select>
  );
});

.classSelect {
  width: 160px;
}

import { comRef } from "mybricks";
import { Button } from "antd";
import { SearchOutlined } from "@ant-design/icons";
import css from "./index.less";

/**
 * @summary 查询按钮
 * @event {queryData} 查询数据 - flowchart LR; A[设置loading状态] --> B[调用 store.fetchScoreList] --> C[取消loading状态]
 */
export default comRef(({ store }) => {
  return (
    <Button
      className={css.queryButton}
      type="primary"
      icon={<SearchOutlined />}
      loading={store.loading}
      /** onClick:queryData */
      onClick={() => store.fetchScoreList()}
    >
      查询
    </Button>
  );
});

.queryButton {
  min-width: 88px;
}

import { comRef } from "mybricks";
import { Table } from "antd";
import css from "./index.less";

/**
 * @summary 成绩列表区
 */
export default comRef(({ store }) => {
  const columns = [
    {
      title: "序号",
      dataIndex: "index",
      key: "index",
      width: 80,
      align: "center",
      render: (_, __, index) => index + 1 + (store.pagination.current - 1) * store.pagination.pageSize,
    },
    {
      title: "学号",
      dataIndex: "studentId",
      key: "studentId",
      width: 120,
    },
    {
      title: "姓名",
      dataIndex: "name",
      key: "name",
      width: 100,
    },
    {
      title: "班级",
      dataIndex: "className",
      key: "className",
      width: 120,
    },
    {
      title: "语文",
      dataIndex: "chinese",
      key: "chinese",
      width: 100,
      align: "center",
      render: (score) => <span className={score < 60 ? css.failScore : ""}>{score}</span>,
    },
    {
      title: "数学",
      dataIndex: "math",
      key: "math",
      width: 100,
      align: "center",
      render: (score) => <span className={score < 60 ? css.failScore : ""}>{score}</span>,
    },
    {
      title: "英语",
      dataIndex: "english",
      key: "english",
      width: 100,
      align: "center",
      render: (score) => <span className={score < 60 ? css.failScore : ""}>{score}</span>,
    },
    {
      title: "总分",
      dataIndex: "total",
      key: "total",
      width: 100,
      align: "center",
      render: (_, record) => {
        const total = record.chinese + record.math + record.english;
        return <span className={css.totalScore}>{total}</span>;
      },
    },
    {
      title: "平均分",
      dataIndex: "average",
      key: "average",
      width: 100,
      align: "center",
      render: (_, record) => {
        const average = ((record.chinese + record.math + record.english) / 3).toFixed(1);
        return <span className={css.averageScore}>{average}</span>;
      },
    },
    {
      title: "排名",
      dataIndex: "rank",
      key: "rank",
      width: 80,
      align: "center",
      render: (rank) => <span className={css.rank}>{rank}</span>,
    },
  ];

  return (
    <div className={css.scoreListContainer}>
      <Table
        className={css.scoreTable}
        columns={columns}
        dataSource={store.scoreList}
        rowKey="id"
        loading={store.loading}
        pagination={false}
        scroll={{ x: 1000 }}
      />
    </div>
  );
});

.scoreListContainer {
  position: relative;
  width: 100%;
  background-color: #fff;
  border-radius: 8px;
  margin-top: 16px;
  padding: 20px 24px;
  flex: 1;
  min-height: 0;
}

.scoreTable {
  :global(.ant-table-thead > tr > th) {
    background-color: #fafafa;
    font-weight: 500;
    color: #262626;
  }
}

.failScore {
  color: #ff4d4f;
  font-weight: 500;
}

.totalScore {
  color: #1890ff;
  font-weight: 600;
}

.averageScore {
  color: #52c41a;
  font-weight: 500;
}

.rank {
  color: #faad14;
  font-weight: 600;
}

import { comRef } from "mybricks";
import { Pagination } from "antd";
import css from "./index.less";

/**
 * @summary 分页区
 * @event {changePage} 切换页码 - flowchart LR; A[调用 store.setPagination] --> B[调用 store.fetchScoreList]
 * @event {changePageSize} 切换每页条数 - flowchart LR; A[调用 store.setPagination] --> B[调用 store.fetchScoreList]
 */
export default comRef(({ store }) => {
  return (
    <div className={css.paginationContainer}>
      <Pagination
        className={css.pagination}
        current={store.pagination.current}
        pageSize={store.pagination.pageSize}
        total={store.pagination.total}
        showSizeChanger
        showQuickJumper
        showTotal={(total) => `共 ${total} 条`}
        pageSizeOptions={["10", "20", "50", "100"]}
        /** onChange:changePage */
        onChange={(page, pageSize) => store.handlePageChange(page, pageSize)}
        /** onShowSizeChange:changePageSize */
        onShowSizeChange={(current, size) => store.handlePageChange(current, size)}
      />
    </div>
  );
});

.paginationContainer {
  position: relative;
  width: 100%;
  height: 56px;
  background-color: #fff;
  border-radius: 8px;
  margin-top: 16px;
  padding: 12px 24px;
  display: flex;
  align-items: center;
  justify-content: flex-end;
  flex-shrink: 0;
}

.pagination {
  :global(.ant-pagination-options) {
    margin-left: 16px;
  }
}

export default class Store {
  // 搜索条件
  searchName = "";
  searchStudentId = "";
  searchClass = undefined;

  // 班级选项
  classOptions = [
    { value: "1", label: "一年级一班" },
    { value: "2", label: "一年级二班" },
    { value: "3", label: "二年级一班" },
    { value: "4", label: "二年级二班" },
    { value: "5", label: "三年级一班" },
    { value: "6", label: "三年级二班" },
  ];

  // 成绩列表数据
  scoreList = [];

  // 加载状态
  loading = false;

  // 分页信息
  pagination = {
    current: 1,
    pageSize: 10,
    total: 0,
  };

  constructor() {
    // 初始化加载数据
    this.fetchScoreList();
  }

  // 设置搜索姓名
  setSearchName(name) {
    this.searchName = name;
  }

  // 设置搜索学号
  setSearchStudentId(studentId) {
    this.searchStudentId = studentId;
  }

  // 设置搜索班级
  setSearchClass(classValue) {
    this.searchClass = classValue;
  }

  // 设置分页
  setPagination(pagination) {
    this.pagination = { ...this.pagination, ...pagination };
  }

  // 处理分页变化
  handlePageChange(page, pageSize) {
    this.setPagination({ current: page, pageSize });
    this.fetchScoreList();
  }

  // 获取成绩列表
  async fetchScoreList() {
    this.loading = true;

    // 模拟异步请求
    await new Promise((resolve) => setTimeout(resolve, 500));

    // 模拟数据
    const mockData = this.generateMockData();

    // 筛选逻辑
    let filteredData = mockData.filter((item) => {
      const matchName = !this.searchName || item.name.includes(this.searchName);
      const matchStudentId = !this.searchStudentId || item.studentId.includes(this.searchStudentId);
      const matchClass = !this.searchClass || item.classId === this.searchClass;
      return matchName && matchStudentId && matchClass;
    });

    // 排序（按总分降序）
    filteredData.sort((a, b) => {
      const totalA = a.chinese + a.math + a.english;
      const totalB = b.chinese + b.math + b.english;
      return totalB - totalA;
    });

    // 添加排名
    filteredData = filteredData.map((item, index) => ({
      ...item,
      rank: index + 1,
    }));

    // 分页
    const { current, pageSize } = this.pagination;
    const start = (current - 1) * pageSize;
    const end = start + pageSize;
    this.scoreList = filteredData.slice(start, end);
    this.pagination.total = filteredData.length;

    this.loading = false;
  }

  // 生成模拟数据
  generateMockData() {
    const names = ["张三", "李四", "王五", "赵六", "钱七", "孙八", "周九", "吴十", "郑十一", "王十二"];
    const classMap = {
      "1": "一年级一班",
      "2": "一年级二班",
      "3": "二年级一班",
      "4": "二年级二班",
      "5": "三年级一班",
      "6": "三年级二班",
    };

    const data = [];
    for (let i = 1; i <= 86; i++) {
      const classId = String(Math.floor(Math.random() * 6) + 1);
      data.push({
        id: i,
        studentId: `2024${String(i).padStart(3, "0")}`,
        name: names[Math.floor(Math.random() * names.length)] + (i > 10 ? i : ""),
        classId: classId,
        className: classMap[classId],
        chinese: Math.floor(Math.random() * 40) + 60, // 60-100
        math: Math.floor(Math.random() * 50) + 50, // 50-100
        english: Math.floor(Math.random() * 45) + 55, // 55-100
      });
    }
    return data;
  }
}
